+    assert_eq!(unsafe { _getlong(std::ptr::null()) }, 0);
+    unsafe { __putshort(0x1234, std::ptr::null_mut()) };
+    unsafe { __putlong(0x1234_5678, std::ptr::null_mut()) };
+}
